const ingresos = Number($ingresos);
const gastos = Number($gastos);
const utilidad = Number($utilidad_neta);
const morosidad = Number($morosidad);

const margenNeto = ingresos ? (utilidad / ingresos) * 100 : 0;
const eficiencia = ingresos ? (gastos / ingresos) * 100 : 0;

let estado, alerta;
if (morosidad < 5) { estado = 'Saludable'; alerta = 'verde'; }
else if (morosidad <= 7) { estado = 'En observacion'; alerta = 'amarillo'; }
else { estado = 'Critica'; alerta = 'rojo'; }

const resultado = {
  sucursal: $sucursal,
  margen_neto_pct: Number(margenNeto.toFixed(1)),
  eficiencia_operativa_pct: Number(eficiencia.toFixed(1)),
  indice_morosidad_pct: morosidad,
  estado_morosidad: estado,
  nivel_alerta: alerta
};
return JSON.stringify(resultado);
